/* =============================================
   MC Auto Sound Design — Cotizador
   js/pdf.js  v3  — Layout fijo 16:9 vertical
   ============================================= */

const BG_BASE64 = "";

function generarPDF(state) {
  const c        = state.cliente;
  const settings = state.settings;

  const fecha = c.fecha
    ? new Date(c.fecha + 'T12:00:00')
        .toLocaleDateString('es-MX', { day: '2-digit', month: 'long', year: 'numeric' })
        .toUpperCase()
    : '\u2014';

  let allRows = '';
  let total   = 0;

  const buildRows = (cat) => {
    Object.entries(state.selected).forEach(([id, entry]) => {
      const item = state.catalog[cat]?.find(i => i.id === id);
      if (!item) return;
      const qty      = entry.qty   || 1;
      const price    = entry.price ?? item.price;
      const subtotal = qty * price;
      total += subtotal;
      const precioFmt   = '$' + price.toLocaleString('es-MX', { minimumFractionDigits: 2 });
      const subtotalFmt = '$' + subtotal.toLocaleString('es-MX', { minimumFractionDigits: 2 });
      const descripcion = item.desc || item.name;
      allRows += `<tr><td class="c-cant">${qty}</td><td class="c-desc">${descripcion}</td><td class="c-pu">${precioFmt}</td><td class="c-imp">${subtotalFmt}</td></tr>`;
    });
  };

  buildRows('venta');
  buildRows('mdo');

  const totalFmt     = '$' + total.toLocaleString('es-MX', { minimumFractionDigits: 2 });
  const dias         = c.dias      || '?';
  const nombre       = (c.nombre   || '\u2014').toUpperCase();
  const vehiculo     = (c.vehiculo || '\u2014').toUpperCase();
  const folio        = state.folio;
  const tallerNombre = settings.taller?.nombre || 'MC Auto Sound Design';
  const nota         = settings.cotizacion?.nota_footer || '';
  const bgUrl        = `data:image/png;base64,${BG_BASE64}`;

  /* ── CSS embebido ── */
  const css = `
    @import url('https://fonts.googleapis.com/css2?family=Cormorant+Garamond:ital,wght@0,300;0,400;1,300;1,400;1,500&family=Montserrat:wght@300;400;500;600&display=swap');

    *, *::before, *::after { margin:0; padding:0; box-sizing:border-box; }

    /* Página fija 16:9 vertical = 1080 × 1920 px equivalente */
    @page { size: 1080px 1920px; margin: 0; }

    html, body {
      width: 1080px;
      height: 1920px;
      overflow: hidden;
      background: #0a0a0a;
      -webkit-print-color-adjust: exact;
      print-color-adjust: exact;
    }

    /* Contenedor raíz — tamaño fijo */
    .sheet {
      position: relative;
      width: 1080px;
      height: 1920px;
      overflow: hidden;
      font-family: 'Montserrat', sans-serif;
      color: #fff;
    }

    /* Fondo */
    .bg {
      position: absolute;
      inset: 0;
      background-image: url('${bgUrl}');
      background-size: cover;
      background-position: center top;
      z-index: 0;
    }
    .overlay {
      position: absolute;
      inset: 0;
      background: rgba(0,0,0,0.62);
      z-index: 1;
    }

    /* Área de contenido — padding interno */
    .content {
      position: absolute;
      inset: 0;
      z-index: 2;
      padding: 80px 72px 72px;
      display: flex;
      flex-direction: column;
    }

    /* ── 1. Nombre del taller centrado ── */
    .logo-block {
      text-align: center;
      padding-bottom: 32px;
      margin-bottom: 36px;
      border-bottom: 1px solid rgba(255,255,255,.18);
      flex-shrink: 0;
    }
    .brand-script {
      font-family: 'Cormorant Garamond', serif;
      font-size: 52px;
      font-weight: 300;
      font-style: italic;
      letter-spacing: .18em;
      color: rgba(255,255,255,.92);
      line-height: 1.2;
    }

    /* ── 2. Cliente + Presupuesto en la misma fila ── */
    .client-header {
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
      margin-bottom: 36px;
      flex-shrink: 0;
    }
    .client-data { flex: 1; }
    .info-line {
      display: flex;
      align-items: baseline;
      gap: 18px;
      margin-bottom: 10px;
    }
    .ilabel {
      font-size: 16px;
      font-weight: 500;
      letter-spacing: .16em;
      text-transform: uppercase;
      color: rgba(255,255,255,.38);
      min-width: 100px;
      flex-shrink: 0;
    }
    .ival {
      font-family: 'Cormorant Garamond', serif;
      font-size: 26px;
      font-weight: 400;
      color: rgba(255,255,255,.92);
      letter-spacing: .05em;
      line-height: 1.3;
    }
    .ival.mono {
      font-family: 'Montserrat', sans-serif;
      font-size: 18px;
      font-weight: 400;
      letter-spacing: .12em;
      color: rgba(255,255,255,.5);
    }
    /* "Presupuesto" alineado a la derecha, mismo nivel que los datos */
    .presupuesto-aside {
      flex-shrink: 0;
      padding-top: 4px;
    }
    .presupuesto-word {
      font-family: 'Cormorant Garamond', serif;
      font-size: 56px;
      font-style: italic;
      font-weight: 300;
      color: #fff;
      letter-spacing: .06em;
      line-height: 1;
    }

    /* ── 3. Texto intro ── */
    .intro-text {
      font-size: 18px;
      font-weight: 300;
      color: rgba(255,255,255,.45);
      line-height: 1.75;
      margin-bottom: 32px;
      font-style: italic;
      padding-left: 18px;
      border-left: 1.5px solid rgba(255,255,255,.18);
      flex-shrink: 0;
    }

    /* ── 4. Tabla ── */
    .table-container {
      border: 1px solid rgba(255,255,255,.16);
      border-radius: 8px;
      overflow: hidden;
      flex-shrink: 0;
    }
    .table-header {
      display: grid;
      grid-template-columns: 60px 1fr 180px 180px;
      padding: 14px 20px;
      background: rgba(255,255,255,.1);
      border-bottom: 1px solid rgba(255,255,255,.14);
    }
    .th {
      font-size: 15px;
      font-weight: 600;
      letter-spacing: .14em;
      text-transform: uppercase;
      color: rgba(255,255,255,.55);
    }
    .th.center { text-align: center; }
    .th.right  { text-align: right; }

    table { width: 100%; border-collapse: collapse; }
    table tr {
      display: grid;
      grid-template-columns: 60px 1fr 180px 180px;
      padding: 13px 20px;
      border-bottom: 1px solid rgba(255,255,255,.07);
    }
    table tr:last-child { border-bottom: none; }
    table tr:nth-child(even) { background: rgba(255,255,255,.03); }

    td {
      font-size: 19px;
      font-weight: 300;
      color: #fff;
      display: flex;
      align-items: center;
    }
    td.c-cant { justify-content: center; color: rgba(255,255,255,.4); font-size: 18px; }
    td.c-desc { font-size: 18px; line-height: 1.45; padding-right: 12px; color: rgba(255,255,255,.88); }
    td.c-pu   { justify-content: flex-end; color: rgba(255,255,255,.55); font-size: 18px; font-family: 'Montserrat', sans-serif; font-weight: 400; }
    td.c-imp  { justify-content: flex-end; font-size: 19px; font-weight: 600; color: #fff; font-family: 'Montserrat', sans-serif; }

    /* ── 5. Subtotal — misma fuente que tabla ── */
    .subtotal-wrap {
      display: flex;
      justify-content: flex-end;
      align-items: baseline;
      gap: 20px;
      padding: 20px 20px 0;
      border-top: 1px solid rgba(255,255,255,.18);
      margin-top: 3px;
      flex-shrink: 0;
    }
    .subtotal-label {
      font-family: 'Montserrat', sans-serif;
      font-size: 15px;
      font-weight: 500;
      letter-spacing: .18em;
      text-transform: uppercase;
      color: rgba(255,255,255,.4);
    }
    /* ← misma familia que td.c-imp */
    .subtotal-val {
      font-family: 'Montserrat', sans-serif;
      font-size: 42px;
      font-weight: 600;
      color: #fff;
      letter-spacing: .02em;
    }

    /* ── 6. Footer pegado al fondo ── */
    .footer {
      margin-top: auto;
      padding-top: 28px;
      border-top: 1px solid rgba(255,255,255,.1);
      flex-shrink: 0;
    }
    .footer-list { list-style: none; display: flex; flex-direction: column; gap: 8px; }
    .footer-list li {
      font-size: 16px;
      font-weight: 300;
      color: rgba(255,255,255,.4);
      line-height: 1.7;
      padding-left: 18px;
      position: relative;
    }
    .footer-list li::before { content: '·'; position: absolute; left: 0; color: rgba(255,255,255,.25); }
    .footer-list strong { color: rgba(255,255,255,.65); font-weight: 500; }

    /* Print */
    @media print {
      html, body { width: 1080px; height: 1920px; overflow: hidden; }
      @page { size: 1080px 1920px; margin: 0; }
    }
  `;

  const html = `<!DOCTYPE html>
<html lang="es"><head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=1080"/>
<title>${folio} \u2014 ${c.nombre || 'Presupuesto'}</title>
<style>${css}</style>
</head><body>
<div class="sheet">
  <div class="bg"></div>
  <div class="overlay"></div>
  <div class="content">

    <div class="logo-block">
      <span class="brand-script">${tallerNombre}</span>
    </div>

    <div class="client-header">
      <div class="client-data">
        <div class="info-line"><span class="ilabel">Fecha</span><span class="ival">${fecha}</span></div>
        <div class="info-line"><span class="ilabel">Cliente</span><span class="ival">${nombre}</span></div>
        <div class="info-line"><span class="ilabel">Veh\u00edculo</span><span class="ival">${vehiculo}</span></div>
        <div class="info-line"><span class="ilabel">Folio</span><span class="ival mono">${folio}</span></div>
      </div>
      <div class="presupuesto-aside">
        <span class="presupuesto-word">Presupuesto</span>
      </div>
    </div>

    <p class="intro-text">Este documento detalla la cotizaci\u00f3n de los productos y servicios recomendados para el veh\u00edculo, basados en nuestra conversaci\u00f3n y en sus necesidades espec\u00edficas. Ofreciendo una soluci\u00f3n personalizada de acuerdo a la calidad seleccionada.</p>

    <div class="table-container">
      <div class="table-header">
        <span class="th center">Cant.</span>
        <span class="th">Descripci\u00f3n</span>
        <span class="th right">P.U.</span>
        <span class="th right">Importe</span>
      </div>
      <table>${allRows}</table>
    </div>

    <div class="subtotal-wrap">
      <span class="subtotal-label">Subtotal</span>
      <span class="subtotal-val">${totalFmt}</span>
    </div>

    <div class="footer">
      <ul class="footer-list">
        <li>${nota}</li>
        <li>El proceso de instalaci\u00f3n y ajuste del sistema de audio tomar\u00e1 aproximadamente <strong>${dias} d\u00eda(s)</strong>, dependiendo de la complejidad del proyecto y los requerimientos espec\u00edficos del veh\u00edculo.</li>
      </ul>
    </div>

  </div>
</div>
</body></html>`;

  const blob = new Blob([html], { type: 'text/html' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  a.href     = url;
  a.download = `${folio}_${(c.nombre || 'presupuesto').replace(/\s+/g, '_')}.html`;
  a.click();
  URL.revokeObjectURL(url);
}
